using AiDotNet.Data.Geometry;

namespace AiDotNet.Data.Text.Benchmarks;

/// <summary>
/// Configuration options for the TinyStories data loader (Eldan &amp; Li, 2023).
/// </summary>
/// <remarks>
/// <para>
/// TinyStories is a synthetic LM corpus generated by GPT-3.5/4 to teach
/// small (10M-param) language models to produce coherent short narratives.
/// ≈ 2.1M training stories, ≈ 22k validation stories. Used to test whether
/// architectural choices help small LMs at all (Eldan &amp; Li 2023, "TinyStories:
/// How Small Can Language Models Be and Still Speak Coherent English?").
/// Files are plain text with each story separated by &lt;|endoftext|&gt;.
/// </para>
/// </remarks>
public sealed class TinyStoriesDataLoaderOptions
{
    /// <summary>Dataset split to load. Default is Train.</summary>
    public DatasetSplit Split { get; set; } = DatasetSplit.Train;
    /// <summary>Root data path. When null, uses default cache path.</summary>
    public string? DataPath { get; set; }
    /// <summary>Automatically download if not present. Default is true.</summary>
    public bool AutoDownload { get; set; } = true;
    /// <summary>Sequence length per training sample. Default is 256.</summary>
    public int SequenceLength { get; set; } = 256;
    /// <summary>Maximum vocabulary size. Default is 16000 — TinyStories has a deliberately small vocabulary.</summary>
    public int VocabularySize { get; set; } = 16000;
    /// <summary>Optional maximum number of samples to load.</summary>
    public int? MaxSamples { get; set; }

    /// <summary>Validates that all option values are within acceptable ranges.</summary>
    /// <exception cref="ArgumentOutOfRangeException">Thrown when any option is invalid.</exception>
    public void Validate()
    {
        if (SequenceLength <= 0) throw new ArgumentOutOfRangeException(nameof(SequenceLength), "SequenceLength must be positive.");
        if (VocabularySize <= 0) throw new ArgumentOutOfRangeException(nameof(VocabularySize), "VocabularySize must be positive.");
        if (MaxSamples is <= 0) throw new ArgumentOutOfRangeException(nameof(MaxSamples), "MaxSamples must be positive when specified.");
    }
}
